import { useEffect, createElement } from "react";
import { MockLink } from "@apollo/client/testing";
import {
  MockedProvider,
  MockedProviderProps,
} from "@apollo/client/testing/react";
import {
  act,
  fireEvent,
  queries,
  render,
  renderHook,
  screen,
  waitFor,
  within,
  waitForElementToBeRemoved,
  type RenderOptions,
  type RenderResult,
} from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { RouterProvider, createMemoryRouter } from "react-router-dom";
import * as customQueries from "./custom-queries";

type QueriesType = typeof queries;
type CustomQueriesType = typeof customQueries;
type CustomRenderType = CustomQueriesType & QueriesType;
type CustomRenderOptions = RenderOptions<CustomRenderType>;

interface RenderWithRouterMatchOptions extends CustomRenderOptions {
  route?: string;
  history?: unknown;
  path?: string;
}

// Bind our custom queries to screen.
// https://github.com/testing-library/dom-testing-library/issues/516
const boundQueries = within<typeof customQueries>(document.body, customQueries);
const customScreen = { ...screen, ...boundQueries };

/**
 * `customRender` or `render` takes an instance of react-testing-library's render method
 *  and adds additional selectors for querying components in tests.
 * @param ui - React Component to render
 * @param options - Options to pass to render
 * @returns RenderResult with custom queries bound to screen
 */
const customRender = (ui: React.ReactElement, options?: CustomRenderOptions) =>
  render(ui, {
    queries: { ...queries, ...customQueries },
    ...options,
  }) as RenderResult<CustomRenderType>;

const customWithin = (ui: HTMLElement) =>
  within(ui, { ...queries, ...customQueries });

/**
 * `renderWithRouterMatch` implements the `customRender` method and wraps a component
 * with an instance of `react-router`'s `<Router />` component.
 * @param ui - React Component to render
 * @param options - Options to pass to render
 * @returns RenderResult with custom queries bound to screen
 */
const renderWithRouterMatch = (
  ui: React.ReactElement,
  options: RenderWithRouterMatchOptions = {},
) => {
  const { path = "/", route = "/", wrapper: TestWrapper, ...rest } = options;

  const getMemoryRouter = (element: React.ReactElement) => {
    const routes = [
      {
        element: TestWrapper ? <TestWrapper>{element}</TestWrapper> : element,
        errorElement: <div>Failed to render component.</div>,
        path,
      },
      {
        element: <div>Not found</div>,
        path: "*",
      },
    ];
    return createMemoryRouter(routes, {
      initialEntries: [route],
    });
  };

  const memoryRouter = getMemoryRouter(ui);

  const { rerender, ...renderRest } = customRender(
    <RouterProvider router={memoryRouter} />,
    {
      ...rest,
    },
  );

  const customRerender = (element: React.ReactElement) => {
    rerender(<RouterProvider router={getMemoryRouter(element)} />);
  };

  return {
    rerender: customRerender,
    router: memoryRouter,
    ...renderRest,
  };
};

/**
 * `renderComponentWithHook` is a utility function that renders a component with a given hook for use in testing
 * @param useHook - The hook to use
 * @param Comp - The component to render
 * @returns - The component and the hook result accessible via hook.current
 */
const renderComponentWithHook = <
  T extends () => unknown,
  U extends React.JSX.Element | null,
>(
  useHook: T,
  Comp: U,
) => {
  const hookRef: { current?: ReturnType<T> } = { current: undefined };

  const TestComponent = () => {
    const hookResult = useHook();
    useEffect(() => {
      hookRef.current = hookResult as ReturnType<T>;
    });
    return Comp;
  };

  return {
    Component: TestComponent,
    hook: hookRef as { current: ReturnType<T> },
  };
};

/**
 * `stubGetClientRects` fixes a fallbackFocus error introduced by focus-trap.
 * focus-trap only offers legacy CommonJS exports so it can't be mocked by Vitest.
 * Instead, spoof focus-trap into thinking there is a node attached.
 * https://stackoverflow.com/a/75527964
 */
const stubGetClientRects = () => {
  const { getClientRects } = HTMLElement.prototype;
  HTMLElement.prototype.getClientRects = function () {
    return {
      ...getClientRects.apply(this),
      length: 1,
    };
  };
};

/**
 * createWrapper provides a generic way to pass props to a React Component wrapper.
 * @param Wrapper - Wrapper component
 * @param props - props to be spread on wrapper
 * @returns - wrapper with props applied
 */
const createWrapper = <T extends Record<string, unknown>>(
  Wrapper: React.ComponentType<React.PropsWithChildren<T>>,
  props: T,
) =>
  function CreatedWrapper({ children }: React.PropsWithChildren) {
    return createElement(Wrapper, props, children);
  };

type MockedResponse = MockLink.MockedResponse;

export {
  act,
  fireEvent,
  customRender as render,
  renderHook,
  renderWithRouterMatch,
  renderComponentWithHook,
  customScreen as screen,
  userEvent,
  waitFor,
  waitForElementToBeRemoved,
  customWithin as within,
  stubGetClientRects,
  createWrapper,
  MockedProvider,
  type MockedResponse,
  type MockedProviderProps,
};

export type { RenderWithRouterMatchOptions };

import {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useReducer,
} from "react";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { getUserStagingKey, isStaging } from "../../utils/environmentVariables";
import {
  SentryBreadcrumbTypes,
  leaveBreadcrumb,
} from "../../utils/errorReporting";
import { fetchWithRetry, getUserStagingHeader } from "../../utils/request";

type AuthProviderDispatchMethods = {
  /**
   * localLogin - used only if `shouldUseLocalAuth` is true.
   * @param credentials - credentials to login with
   * @param credentials.username - username
   * @param credentials.password - password
   */
  localLogin: (credentials: { username: string; password: string }) => void;
  /**
   * logoutAndRedirect - calls the logout endpoint for localAuth
   * or redirects to the remoteAuthURL for remoteAuth.
   */
  logoutAndRedirect: () => void;
  /**
   * A helper to mark the user as authenticated in local state
   * (useful if you get a successful check from somewhere else).
   */
  dispatchAuthenticated: () => void;
};

type AuthState = {
  /**
   * `isAuthenticated` is a boolean that determines whether the user is currently authenticated.
   */
  isAuthenticated: boolean;
  /**
   * `hasCheckedAuth` is a boolean that determines whether the user's authentication status has been checked.
   * This is useful for determining whether to show a loading spinner or not.
   */
  hasCheckedAuth: boolean;
};

const AuthStateContext = createContext<
  (AuthState & AuthProviderDispatchMethods) | null
>(null);

type AuthAction = { type: "SET_AUTH"; payload: boolean };

const authReducer = (state: AuthState, action: AuthAction): AuthState => {
  switch (action.type) {
    case "SET_AUTH":
      return { isAuthenticated: action.payload, hasCheckedAuth: true };
    default:
      return state;
  }
};

/**
 * `AuthProvider` is a context provider that manages the authentication state of the application.
 * It provides support for both local and remote authentication strategies.
 * localAuthentication is used for local development when connected to a local development environment and remoteAuthentication is used for production or when connected to a remote development environment.
 * @param props -
 * @param props.children - The children of the AuthProvider component.
 * @param props.localAuthRoute - The route of the local authentication provider UI. (Only used in local development)
 * @param props.remoteAuthURL - The URL that we should redirect the user to if they are not currently authenticated when `shouldUseLocalAuth` is false.
 * @param props.shouldUseLocalAuth - A boolean that determines which authentication strategy we should use.
 * @param props.evergreenAppURL - The URL of the evergreen instance we will authenticate against.
 * @returns - The AuthProvider component.
 */
const AuthProvider: React.FC<{
  children: React.ReactNode;
  /** `evergreenAppURL` is the URL of the evergreen instance we will authenticate against */
  evergreenAppURL: string;
  /** `remoteAuthURL` is the URL that we should redirect the user to if they are not currently authenticated when `shouldUseLocalAuth` is false */
  remoteAuthURL: string;
  /** `localAuthRoute` is the route that we should redirect the user to if they are not currently authenticated when `shouldUseLocalAuth` is true */
  localAuthRoute: string;
  /** `shouldUseLocalAuth` determines which authentication strategy we should use. */
  shouldUseLocalAuth: boolean;
}> = ({
  children,
  evergreenAppURL,
  localAuthRoute,
  remoteAuthURL,
  shouldUseLocalAuth,
}) => {
  const [state, dispatch] = useReducer(authReducer, {
    isAuthenticated: false,
    hasCheckedAuth: false,
  });

  const navigate = useNavigate();

  const authMethods: AuthProviderDispatchMethods = useMemo(
    () => ({
      /**
       * localLogin - used only if `shouldUseLocalAuth` is true.
       * @param credentials - credentials to login with
       * @param credentials.username - username
       * @param credentials.password - password
       */
      localLogin: async ({
        password,
        username,
      }: {
        username: string;
        password: string;
      }) => {
        await fetch(`${evergreenAppURL}/login`, {
          body: JSON.stringify({ password, username }),
          credentials: "include",
          method: "POST",
        }).then((response) => {
          // Dispatch once so that hasCheckedAuth is set to true along with isAuthenticated.
          dispatch({ type: "SET_AUTH", payload: response.ok });
          if (!response.ok) {
            // I know we don't like using alerts but this is a dev only feature
            alert("Error logging in, username or password invalid");
          }
        });
      },
      /**
       * logoutAndRedirect - calls the logout endpoint for localAuth
       * or redirects to the remoteAuthURL for remoteAuth.
       */
      logoutAndRedirect: async () => {
        // Set the staging cookie whether or not the state is currently authenticated so personal stagings can be routed correctly.
        const stagingKey = getUserStagingKey();
        if (isStaging() && stagingKey) {
          Cookies.set("evg-staging-environment", stagingKey, {
            expires: 365,
          });
        }
        if (state.isAuthenticated) {
          try {
            await fetch(`${evergreenAppURL}/logout`, {
              credentials: "include",
              method: "GET",
              redirect: "manual",
              headers: getUserStagingHeader(),
            });
          } catch (error) {
            leaveBreadcrumb(
              "logoutAndRedirect",
              { error },
              SentryBreadcrumbTypes.Error,
            );
          }
        }
        // Reset auth state.
        if (shouldUseLocalAuth) {
          dispatch({ type: "SET_AUTH", payload: false });
          navigate(localAuthRoute);
        } else {
          const encodedOrigin = encodeURIComponent(window.location.href);
          const redirectURL = `${remoteAuthURL}?redirect=${encodedOrigin}`;
          window.location.href = redirectURL;
        }
      },
      /**
       * A helper to mark the user as authenticated in local state.
       */
      dispatchAuthenticated: () => {
        leaveBreadcrumb("User authenticated", {}, SentryBreadcrumbTypes.User);
        dispatch({ type: "SET_AUTH", payload: true });
      },
    }),
    [
      state.isAuthenticated,
      evergreenAppURL,
      localAuthRoute,
      remoteAuthURL,
      shouldUseLocalAuth,
      navigate,
    ],
  );

  useEffect(() => {
    // Testing if the user is authenticated
    fetchWithRetry(`${evergreenAppURL}/graphql/query`, {
      credentials: "include",
      headers: {
        ...getUserStagingHeader(),
        "content-type": "application/json",
      },
      body: JSON.stringify({
        query: "{\n  user {\n    userId\n  }\n}",
        variables: {},
      }),
      method: "POST",
      mode: "cors",
    })
      .then(() => {
        dispatch({ type: "SET_AUTH", payload: true });
      })
      .catch(() => {
        dispatch({ type: "SET_AUTH", payload: false });
        authMethods.logoutAndRedirect();
      });
  }, [evergreenAppURL, authMethods]);

  const authProviderValue = useMemo(
    () => ({
      isAuthenticated: state.isAuthenticated,
      hasCheckedAuth: state.hasCheckedAuth,
      ...authMethods,
    }),
    [state, authMethods],
  );

  return (
    <AuthStateContext.Provider value={authProviderValue}>
      {children}
    </AuthStateContext.Provider>
  );
};

const useAuthProviderContext = (): AuthState & AuthProviderDispatchMethods => {
  const authState = useContext(AuthStateContext);
  if (authState === null || authState === undefined) {
    throw new Error(
      "useAuthStateContext must be used within an auth context provider",
    );
  }
  return authState;
};

export { AuthProvider, useAuthProviderContext };

import {
  ReactNode,
  createContext,
  useCallback,
  useContext,
  useMemo,
} from "react";
import {
  ToastProvider as LGToastProvider,
  Variant,
  useToast,
} from "@leafygreen-ui/toast";
import { WordBreak } from "../../components/styles";
import {
  TOAST_TIMEOUT,
  mapLeafyGreenVariantToTitle,
  mapLeafyGreenVariantToToast,
} from "./constants";
import { DispatchToast, DispatchToastWithProgress, ToastParams } from "./types";

interface ToastContextState {
  success: DispatchToast;
  warning: DispatchToast;
  error: DispatchToast;
  info: DispatchToast;
  progress: DispatchToastWithProgress;
}

export const ToastContext = createContext<ToastContextState | null>(null);

const useToastContext = (): ToastContextState => {
  const context = useContext(ToastContext);
  if (context === null || context === undefined) {
    throw new Error("useToastContext must be used within a ToastProvider");
  }
  return context;
};

const ToastProviderCore: React.FC<{ children: ReactNode }> = ({ children }) => {
  const { pushToast } = useToast();
  const dispatchToast = useCallback(
    ({
      closable,
      message,
      onClose,
      progress,
      shouldTimeout,
      timeout,
      title,
      variant,
    }: ToastParams) => {
      let toastTimeout = null;
      if (timeout !== undefined) {
        toastTimeout = timeout;
      } else if (shouldTimeout) {
        toastTimeout = TOAST_TIMEOUT;
      }

      return pushToast({
        // @ts-expect-error: data-cy doesn't exist as a prop on Toast but it will be propagated correctly.
        "data-cy": "toast",
        "data-variant": mapLeafyGreenVariantToToast[variant],
        description: <WordBreak>{message}</WordBreak>,
        dismissible: closable,
        onClose: closable ? onClose : undefined,
        progress,
        timeout: toastTimeout,
        title: title || mapLeafyGreenVariantToTitle[variant],
        variant,
      });
    },
    [pushToast],
  );

  const toastContext: ToastContextState = useMemo(() => {
    const defaultOptions = {
      onClose: () => {},
      shouldTimeout: true,
      title: "",
    };

    return {
      error: (message = "", closable = true, options = {}) =>
        dispatchToast({
          closable,
          message,
          variant: Variant.Warning,
          ...defaultOptions,
          ...options,
        }),
      info: (message = "", closable = true, options = {}) =>
        dispatchToast({
          closable,
          message,
          variant: Variant.Note,
          ...defaultOptions,
          ...options,
        }),
      progress: (message = "", progress = 0.5, closable = true, options = {}) =>
        dispatchToast({
          closable,
          message,
          progress,
          variant: Variant.Progress,
          ...defaultOptions,
          ...options,
        }),
      success: (message = "", closable = true, options = {}) =>
        dispatchToast({
          closable,
          message,
          variant: Variant.Success,
          ...defaultOptions,
          ...options,
        }),
      warning: (message = "", closable = true, options = {}) =>
        dispatchToast({
          closable,
          message,
          variant: Variant.Important,
          ...defaultOptions,
          ...options,
        }),
    };
  }, [dispatchToast]);

  return (
    <ToastContext.Provider value={toastContext}>
      {children}
    </ToastContext.Provider>
  );
};

const ToastProvider: React.FC<{
