  return { adminBetaSettings: betaFeatures, loading };
};

/**
 * `useUserBetaFeatures` returns the user's beta feature settings.
 * @returns an object containing
 * - userBetaSettings: user's beta features settings
 * - loading: boolean representing query loading state
 */
export const useUserBetaFeatures = () => {
  const { data, loading } = useQuery<
    UserBetaFeaturesQuery,
    UserBetaFeaturesQueryVariables
  >(USER_BETA_FEATURES, {
    variables: {},
  });
  const { user } = data ?? {};
  const { betaFeatures } = user ?? {};
  return { userBetaSettings: betaFeatures, loading };
};

/**
 * `useMergedBetaFeatures` returns the result of merging admin and user level beta features.
 * @returns an object containing
 * - betaFeatures: merged beta features
 * - loading: boolean representing query loading state
 */
export const useMergedBetaFeatures = () => {
  const { adminBetaSettings, loading: adminLoading } = useAdminBetaFeatures();
  const { loading: userLoading, userBetaSettings } = useUserBetaFeatures();

  if (!adminBetaSettings || !userBetaSettings) {
    return { mergedBetaFeatures: undefined, loading: false };
  }

  const mergedBetaFeatures: BetaFeatures = {};

  return {
    betaFeatures: mergedBetaFeatures,
    loading: adminLoading || userLoading,
  };
};

import { useCallback } from "react";
import {
  RECENT_PAGE_SIZE_KEY,
  PaginationQueryParams,
} from "../../constants/pagination";
import { getDefaultPageSize } from "../../utils/pagination";
import { useQueryParam, useQueryParams } from "../useQueryParam";

/**
 * `usePagination` is a hook that manages the page and page size query params
 * It also saves the page size to local storage so that it can be remembered between sessions
 * Updating the page size will reset the page to 0
 * @returns - an object containing the current page, page size limit, and functions to update the page and page limit
 */
const usePagination = () => {
  const [queryParams, setQueryParams] = useQueryParams();
  const [page, setPage] = useQueryParam(PaginationQueryParams.Page, 0);
  const [limit] = useQueryParam(
    PaginationQueryParams.Limit,
    getDefaultPageSize(),
  );

  /**
   * `setLimit` updates the page size query param and saves the page size to local storage
   * @param pageSize - the new page size
   */
  const setLimit = useCallback(
    (pageSize: number) => {
      localStorage.setItem(RECENT_PAGE_SIZE_KEY, pageSize.toString());
      setQueryParams({
        ...queryParams,
        [PaginationQueryParams.Limit]: pageSize,
        [PaginationQueryParams.Page]: 0,
      });
    },
    [queryParams, setQueryParams],
  );

  return { page, limit, setLimit, setPage };
};

export default usePagination;

